93	// Validate validates the configuration structure and values (simplified)
94	func (c *Config) Validate() error {
95		var errors []*ConfigError
96	
97		// Validate version
98		if c.Version == "" {
99			errors = append(errors, &ConfigError{
100				Field:      "version",
101				Message:    "version is required",
102				Suggestion: "add 'version: \"1.0\"' to your config",
103			})
104		}
105	
106		// Validate library configuration
107		if c.Library != nil && c.Library.Repository != nil {
108			if c.Library.Repository.URL == "" {
109				errors = append(errors, &ConfigError{
110					Field:      "library.repository.url",
111					Message:    "library repository URL is required",
112					Suggestion: "add a valid Git repository URL",
113				})
114			}
115	
116			if c.Library.Repository.Branch == "" {
