178	// ResolveLibraryResource resolves a library resource path
179	// NOTE: This function is now legacy. New code should load config and use cfg.Library.Path directly.
180	func ResolveLibraryResource(resourcePath, configPath, workingDir string) (string, error) {
181		// Load config to get the authoritative library path (which includes env var override)
182		cfg, err := LoadWithWorkingDir(workingDir)
183		if err == nil && cfg.Library != nil && cfg.Library.Path != "" {
184			// Check if it's an absolute path
185			if filepath.IsAbs(resourcePath) {
186				return resourcePath, nil
187			}
188	
189			// Try relative to library path from config
190			configPath := filepath.Join(cfg.Library.Path, resourcePath)
191			if _, err := os.Stat(configPath); err == nil {
192				return configPath, nil
193			}
194	
195			// Return the config path even if it doesn't exist (for consistency)
196			return configPath, nil
197		}
198	
199		// Fall back to original logic if config loading fails
200		if workingDir == "" {
201			workingDir, err = os.Getwd()
202			if err != nil {
203				return "", err
204			}
205		}
206	
207		// Check if it's an absolute path
208		if filepath.IsAbs(resourcePath) {
209			return resourcePath, nil
210		}
211	
212		// Try relative to working directory first
213		fullPath := filepath.Join(workingDir, resourcePath)
214		if _, err := os.Stat(fullPath); err == nil {
215			return fullPath, nil
216		}
217	
218		// Try relative to library directory
219		libraryPath := filepath.Join(workingDir, "library", resourcePath)
220		if _, err := os.Stat(libraryPath); err == nil {
221			return libraryPath, nil
222		}
223	
224		// Return the original path even if it doesn't exist
225		return fullPath, nil
226	}
