28	// ResolveProfileLadderCallCount returns the current value of the call counter.
29	// Tests use it together with ResetRoutingCallCounters to verify call-graph claims.
30	func ResolveProfileLadderCallCount() int64 { return resolveProfileLadderCalls.Load() }
