78	func tierWithinBounds(tier, minTier, maxTier string) bool {
79		rank, ok := profileTierRank[tier]
80		if !ok {
81			return minTier == "" && maxTier == ""
82		}
83		if minTier != "" {
84			if minRank, ok := profileTierRank[minTier]; ok && rank < minRank {
85				return false
86			}
87		}
88		if maxTier != "" {
89			if maxRank, ok := profileTierRank[maxTier]; ok && rank > maxRank {
90				return false
91			}
92		}
93		return true
94	}
