13			for k, v := range a.Models {
14				out.Models[k] = v
15			}
16		}
17		if a.ReasoningLevels != nil {
18			out.ReasoningLevels = make(map[string][]string, len(a.ReasoningLevels))
19			for k, v := range a.ReasoningLevels {
20				out.ReasoningLevels[k] = append([]string(nil), v...)
